// Express Middleware Configuration for Static Assets

// Audio files optimization
export const audioOptimizationMiddleware = (req, res, next) => {
  if (req.path.match(/\.(mp3|wav|ogg|m4a)$/i)) {
    res.setHeader('Cache-Control', 'public, max-age=31536000, immutable');
    res.setHeader('X-Content-Type-Options', 'nosniff');
    res.setHeader('Accept-Ranges', 'bytes');
    res.setHeader('Vary', 'Accept-Encoding');
  }
  next();
};

// Image files optimization
export const imageOptimizationMiddleware = (req, res, next) => {
  if (req.path.match(/\.(png|jpg|jpeg|gif|webp|svg|ico)$/i)) {
    res.setHeader('Cache-Control', 'public, max-age=31536000, must-revalidate');
    res.setHeader('X-Content-Type-Options', 'nosniff');
    res.setHeader('Vary', 'Accept-Encoding');
  }
  next();
};

// JavaScript and CSS optimization
export const assetOptimizationMiddleware = (req, res, next) => {
  if (req.path.match(/\.(js|css)$/i)) {
    res.setHeader('Cache-Control', 'public, max-age=31536000, immutable');
    res.setHeader('X-Content-Type-Options', 'nosniff');
    res.setHeader('Vary', 'Accept-Encoding');
  }
  next();
};

// Static HTML pages optimization
export const staticPageOptimizationMiddleware = (req, res, next) => {
  if (req.path.match(/\.(html)$/i) || req.headers['x-static-page']) {
    res.setHeader('Cache-Control', 'public, max-age=3600, must-revalidate');
    res.setHeader('X-Static-Generated', 'true');
    res.setHeader('Vary', 'Accept-Encoding');
  }
  next();
};

// CDN optimization headers
export const cdnOptimizationMiddleware = (req, res, next) => {
  // Set headers for CDN optimization
  if (process.env.NODE_ENV === 'production') {
    res.setHeader('X-Served-By', 'Cosmic-Channeling-v2');
    res.setHeader('X-Optimization-Level', 'maximum');
  }
  next();
};
